/** How often to re-fetch live data from the backend (ms) */
const POLL_INTERVAL = 30_000;

function getStoredCountry(): string {
  try {
    const raw = localStorage.getItem("flyn_onboarding_data");
    if (raw) {
      const parsed = JSON.parse(raw);
      if (parsed?.country) return parsed.country;
    }
  } catch { /* ignore */ }
  return "US";
}

