  // Ask HR AI conversation history
  const [hrConversation, setHrConversation] = useState<Array<{role: 'user'|'ai'; content: string}>>([]);
  const hrChatEndRef = useRef<HTMLDivElement>(null);
  // JD Generator form state
  const [jdDepartment, setJdDepartment] = useState('Engineering');
