      // Active employees are interviewers, not candidates
      const interviewers = allEmployees
        .filter((r: any) => !hiringStatuses.includes(r.status))
        .map((r: any) => r.name || r.employeeName || r.fullName || "Unknown")
        .filter(Boolean);
      // CV pre-fill: if coming from CV parse, put that candidate first
      const prefilledCandidate = pendingScheduleCandidateRef.current;
