      if (!rawText.trim() || rawText.trim().length < 100) {
        throw new Error('Very little text was extracted from this file — it may be a scanned/image PDF. Please copy-paste your CV text using the "Type Info" tab instead.');
      }
      const jd = cvJdText.trim();
      toast({ title: `Extracted ${rawText.length.toLocaleString()} characters`, description: jd ? "Scoring against JD (ATS mode)…" : "Sending to AI for analysis…" });
      const res = await hrService.parseCV({ rawText, jdText: jd || undefined });
